<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Bouncing Ball Playground</title>
<style>
  :root {
    --bg: #0e1117;
    --panel: #161b22;
    --accent: #58a6ff;
    --text: #e6edf3;
    --border: #30363d;
  }
  * { box-sizing: border-box; }
  html, body {
    margin: 0;
    height: 100%;
    background: var(--bg);
    color: var(--text);
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  }
  body {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    gap: 18px;
    padding: 24px;
  }
  h1 {
    font-size: 1.25rem;
    font-weight: 600;
    letter-spacing: 0.3px;
    margin: 0;
    color: var(--text);
  }
  #sim {
    background: radial-gradient(circle at 50% 30%, #1c2330, #0b0e14);
    border: 1px solid var(--border);
    border-radius: 12px;
    box-shadow: 0 10px 40px rgba(0,0,0,0.6);
    cursor: crosshair;
    display: block;
  }
  .controls {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    justify-content: center;
  }
  button {
    background: var(--panel);
    color: var(--text);
    border: 1px solid var(--border);
    padding: 9px 18px;
    border-radius: 8px;
    font-size: 0.9rem;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s, transform 0.05s;
  }
  button:hover {
    background: #21262d;
    border-color: var(--accent);
  }
  button:active { transform: translateY(1px); }
  #play { min-width: 92px; }
  .hint {
    font-size: 0.8rem;
    color: #8b949e;
    margin: 0;
  }
</style>
</head>
<body>
  <h1>Bouncing Ball Playground</h1>
  <canvas id="sim" width="520" height="440"></canvas>
  <div class="controls">
    <button id="drop">Drop ball</button>
    <button id="play">Pause</button>
    <button id="clear">Clear</button>
  </div>
  <p class="hint">Click the canvas to spawn a ball at the cursor.</p>

<script>
(function () {
  "use strict";

  const canvas = document.getElementById("sim");
  const ctx = canvas.getContext("2d");
  const W = canvas.width;
  const H = canvas.height;

  const GRAVITY = 0.35;      // downward acceleration per step
  const RESTITUTION = 0.82;  // energy retained on bounce
  const FRICTION = 0.999;    // slight horizontal damping
  const DEFAULT_R = 14;

  const balls = [];

  const COLORS = [
    "#58a6ff", "#f778ba", "#3fb950", "#d29922",
    "#a371f7", "#ff7b72", "#39c5cf", "#e3b341"
  ];
  let colorIndex = 0;

  function makeBall(x, y, vx, vy, r) {
    r = (typeof r === "number" && r > 0) ? r : DEFAULT_R;
    // keep initial position inside the canvas
    x = Math.min(Math.max(x, r), W - r);
    y = Math.min(Math.max(y, r), H - r);
    const b = {
      x: x,
      y: y,
      vx: vx || 0,
      vy: vy || 0,
      r: r,
      color: COLORS[colorIndex % COLORS.length]
    };
    colorIndex++;
    return b;
  }

  function integrate(b, dt) {
    // gravity
    b.vy += GRAVITY * dt;
    // move
    b.x += b.vx * dt;
    b.y += b.vy * dt;
    b.vx *= FRICTION;

    // walls (left / right)
    if (b.x - b.r < 0) {
      b.x = b.r;
      b.vx = -b.vx * RESTITUTION;
    } else if (b.x + b.r > W) {
      b.x = W - b.r;
      b.vx = -b.vx * RESTITUTION;
    }

    // floor / ceiling
    if (b.y - b.r < 0) {
      b.y = b.r;
      b.vy = -b.vy * RESTITUTION;
    } else if (b.y + b.r > H) {
      b.y = H - b.r;
      b.vy = -b.vy * RESTITUTION;
    }
  }

  function step(dt) {
    dt = (typeof dt === "number" && dt > 0) ? dt : 1;
    for (let i = 0; i < balls.length; i++) {
      integrate(balls[i], dt);
    }
    draw();
  }

  function draw() {
    ctx.clearRect(0, 0, W, H);
    for (let i = 0; i < balls.length; i++) {
      const b = balls[i];
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fillStyle = b.color;
      ctx.fill();
      // subtle highlight for a glossy look
      ctx.beginPath();
      ctx.arc(b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.35, 0, Math.PI * 2);
      ctx.fillStyle = "rgba(255,255,255,0.28)";
      ctx.fill();
    }
  }

  // ---- animation loop ----
  let playing = true;
  const playBtn = document.getElementById("play");

  function frame() {
    if (playing) step(1);
    requestAnimationFrame(frame);
  }
  requestAnimationFrame(frame);

  // ---- controls ----
  document.getElementById("drop").addEventListener("click", function () {
    const x = b_rand(DEFAULT_R, W - DEFAULT_R);
    balls.push(makeBall(x, DEFAULT_R + 4, (Math.random() - 0.5) * 6, 0, DEFAULT_R));
  });

  playBtn.addEventListener("click", function () {
    playing = !playing;
    playBtn.textContent = playing ? "Pause" : "Play";
  });

  document.getElementById("clear").addEventListener("click", function () {
    balls.length = 0;
    draw();
  });

  canvas.addEventListener("click", function (e) {
    const rect = canvas.getBoundingClientRect();
    // account for CSS scaling vs. internal resolution
    const scaleX = W / rect.width;
    const scaleY = H / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;
    balls.push(makeBall(x, y, (Math.random() - 0.5) * 4, 0, DEFAULT_R));
  });

  function b_rand(lo, hi) {
    return lo + Math.random() * (hi - lo);
  }

  // ---- programmatic API ----
  window.sim = {
    w: W,
    h: H,
    balls: function () {
      return balls.map(function (b) {
        return { x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r };
      });
    },
    addBall: function (x, y, vx, vy, r) {
      const b = makeBall(x, y, vx, vy, r);
      balls.push(b);
      draw();
      return { x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r };
    },
    clear: function () {
      balls.length = 0;
      draw();
    },
    step: step
  };

  // seed one ball so the canvas isn't empty on load
  balls.push(makeBall(W * 0.5, H * 0.25, 3, 0, DEFAULT_R));
  draw();
})();
</script>
</body>
</html>
